#### 直接通过 awk 读取文件，然后在 NF字段数 的范围内通过 $i 下标遍历

awk '{
    for (i = 1; i <= NF; i++) {
        seen[$i]++
    }
}
END {
    for (w in seen)
        print w, seen[w]
}' "$1"

#### 2. awk

ls -l | awk '
NR > 1 { sum[$4] += $5 }
END {
    for (g in sum)
        print g, sum[g]
}'

#### }' "$p"

awk '{
    for (i=1;i<=NF;i++){
        $i = toupper($i)
    }
    print
}' "$p" > tmp

#### 或者一口气直接全转了，因为toupper支持

awk '{
    print toupper($0)
}' "$p" > tmp
mv tmp "$p"

