#### 感觉用 awk 统计更自然

awk '{
    delete cnt
    for (i = 1; i <= NF; i++) {
        cnt[$i]++
        if (cnt[$i] == 3) {
            print
            break
        }
    }
}' "$1"

#### 09_2-05

p=$(pwd)/test-files/09_2-05.txt

awk '{
    for (i=1;i<=NF;i++){
        # if( !($i ~ /([A-Z])[a-z]*1/) )
        # awk 中不能用回溯引用 \1
        # 那么就只能先判断格式再 单独判断回溯
        if( !(($i ~ /^[A-Z][a-z]*[A-Z]$/ || $i ~ /^[A-Z]$/) && substr($i,1,1) == substr($i,length($i),1)))
            # 注意 $i ~ /^[A-Z]$/ 单个大写字母也是符合要求的
            exit 1
    }
}

